import { useState } from 'react'
import { Button } from '@/components/ui/button'
import { diagnosticQuestions } from '@/constants/diagnosticQuestions'
import { ArrowLeft, Building2, CheckCircle2 } from 'lucide-react'

interface AssessmentData {
  q1_operational_drag: string
  q2_delay_cause: string
  q3_manual_percentage: string
  q4_exception_tracking: string
  q5_systems_count: string
  q6_system_coordination: string
  q7_rework_frequency: string
  q8_insight_latency: string
}

interface AssessmentScreenProps {
  initialData?: any
  onContinue?: (data: AssessmentData) => void
  onBack?: () => void
  currentStep: number
}

 

export function AssessmentScreen({ initialData, onContinue, onBack }: AssessmentScreenProps) {
  const [assessmentData, setAssessmentData] = useState<AssessmentData>(
    initialData || {
      q1_operational_drag: '',
      q2_delay_cause: '',
      q3_manual_percentage: '',
      q4_exception_tracking: '',
      q5_systems_count: '',
      q6_system_coordination: '',
      q7_rework_frequency: '',
      q8_insight_latency: '',
    }
  )

  const [currentQuestionIndex, setCurrentQuestionIndex] = useState(0)
  const [isAnimating, setIsAnimating] = useState(false)

  const totalQuestions = 8
  const completedQuestions = Object.values(assessmentData).filter((v) => v !== '').length

  const currentQuestion = diagnosticQuestions[currentQuestionIndex]
  const currentAnswer = assessmentData[currentQuestion.id as keyof AssessmentData]
  const completionPercent = (completedQuestions / totalQuestions) * 100

  const handleAnswerSelect = (value: string) => {
    if (isAnimating) return

    const updatedData = {
      ...assessmentData,
      [currentQuestion.id]: value,
    }

    setAssessmentData(updatedData)
    setIsAnimating(true)

    const isLastQuestion = currentQuestionIndex === totalQuestions - 1

    setTimeout(() => {
      if (isLastQuestion) {
        if (onContinue) {
          onContinue(updatedData)
        }
      } else {
        setCurrentQuestionIndex(currentQuestionIndex + 1)
      }
      setIsAnimating(false)
    }, 400)
  }

  const currentSection = currentQuestion.section
  const isNewSection =
    currentQuestionIndex === 0 || diagnosticQuestions[currentQuestionIndex - 1]?.section !== currentSection

  const handleBack = () => {
    if (currentQuestionIndex > 0) {
      setCurrentQuestionIndex((prev) => prev - 1)
      return
    }
    onBack?.()
  }

  return (
    <div className="min-h-screen bg-gradient-to-b from-background to-muted/20">
      <div className="border-b bg-background/80 backdrop-blur-md sticky top-0 z-10">
        <div className="max-w-4xl mx-auto px-6 py-5">
          <div className="flex items-center justify-between">
            {currentQuestionIndex > 0 ? (
              <Button onClick={handleBack} className="text-muted-foreground hover:text-foreground">
                <ArrowLeft className="w-4 h-4 mr-2" />
                Back
              </Button>
            ) : (
              <div className="h-9 w-16" />
            )}
            <div className="flex items-center gap-4">
              <div className="flex gap-2">
                {[1, 2, 3, 4].map((segment) => {
                  const segmentQuestions = diagnosticQuestions.filter((q) => q.sectionNumber === segment)
                  const completedInSegment = segmentQuestions.filter(
                    (q) => assessmentData[q.id as keyof AssessmentData] !== ''
                  ).length
                  const progressPercent = (completedInSegment / segmentQuestions.length) * 100

                  return (
                    <div key={segment} className="w-16 h-1.5 bg-muted rounded-full overflow-hidden">
                      <div className="h-full bg-primary transition-all duration-500" style={{ width: `${progressPercent}%` }} />
                    </div>
                  )
                })}
              </div>
            </div>
          </div>
        </div>
      </div>

      <div className="max-w-4xl mx-auto px-6 py-16">
        <div className="mb-10 bg-redwood-forest border border-redwood-teal/40 rounded-2xl p-6 shadow-xl">
          <div className="flex items-start gap-3 mb-5">
            <Building2 className="h-5 w-5 text-primary mt-1 shrink-0" />
            <div>
              <h1 className="text-3xl font-bold text-primary">Financial drag assessment</h1>
              <p className="text-redwood-light-teal mt-1">Financial close process evaluation</p>
            </div>
          </div>

          <div className="w-full h-2 bg-redwood-teal/30 rounded-full overflow-hidden mb-3">
            <div className="h-full bg-primary transition-all duration-500" style={{ width: `${completionPercent}%` }} />
          </div>
          <p className="text-sm text-redwood-light-teal">
            {currentSection} - {completedQuestions} of {totalQuestions} questions completed
          </p>
        </div>

        {isNewSection && (
          <div className="mb-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
            <div className="inline-flex items-center gap-3 bg-primary/10 px-6 py-3 rounded-full border border-primary/20 mb-4">
              <div className="w-8 h-8 rounded-full bg-primary text-primary-foreground flex items-center justify-center text-sm font-bold">
                {currentQuestion.sectionNumber}
              </div>
              <span className="font-semibold text-lg text-foreground">{currentSection}</span>
            </div>
          </div>
        )}

        <div className="animate-in fade-in slide-in-from-right-4 duration-300" key={currentQuestionIndex}>
          <div className="bg-card border-2 border-border rounded-3xl shadow-2xl p-10 w-full">
            <div className="mb-8">
              <div className="text-sm font-medium text-muted-foreground mb-3">
                Question {currentQuestionIndex + 1} of {totalQuestions}
              </div>
              <h2 className="text-3xl font-bold text-foreground leading-tight">{currentQuestion.heading}</h2>
            </div>

            <div className="space-y-3">
              {currentQuestion.options.map((option) => {
                const isSelected = currentAnswer === option.value
                return (
                  <button
                    key={option.value}
                    onClick={() => handleAnswerSelect(option.value)}
                    disabled={isAnimating}
                    className={`w-full text-left px-8 py-5 rounded-2xl border-2 transition-all duration-200 ${
                      isSelected
                        ? 'bg-primary border-primary text-primary-foreground shadow-lg scale-[1.02]'
                        : 'bg-background border-border hover:border-primary/50 hover:bg-primary/5 text-foreground'
                    } ${isAnimating ? 'cursor-not-allowed opacity-70' : 'cursor-pointer'}`}
                  >
                    <div className="flex items-center justify-between">
                      <span className="font-medium text-lg">{option.label}</span>
                      {isSelected && <CheckCircle2 className="w-6 h-6 flex-shrink-0 animate-in zoom-in duration-200" />}
                    </div>
                  </button>
                )
              })}
            </div>
          </div>
        </div>
      </div>
    </div>
  )
}
